import { ColourSwatch } from "@/components/ColourSwatch";
import { generatePalettes } from "@/lib/palette";

export default function Home() {
  const palettes = generatePalettes("#3b82f6"); // Blue-500
  const monoPalette = palettes.find(p => p.type === "monochromatic");

  return (
    <main className="flex min-h-screen flex-col items-center justify-center p-8 bg-brand-slate-50">
      <div className="max-w-4xl w-full">
        <header className="mb-12 text-center">
          <h1 className="text-5xl font-extrabold tracking-tight text-brand-slate-900 mb-4">
            PaletteForge <span className="text-brand-rose-500">Preview</span>
          </h1>
          <p className="text-brand-slate-600 text-lg">
            A premium color engine for modern designers.
          </p>
        </header>

        {monoPalette && (
          <div className="bg-white p-8 rounded-2xl shadow-xl border border-brand-slate-200">
            <h2 className="text-xl font-bold mb-6 text-brand-slate-800">Monochromatic Swatches (Blue-500)</h2>
            <div className="flex gap-0 overflow-hidden rounded-xl border border-brand-slate-200">
              {monoPalette.colours.map((colour, i) => (
                <ColourSwatch 
                  key={colour.hex} 
                  colour={colour} 
                  size="lg"
                  position={
                    i === 0 ? "first" : 
                    i === monoPalette.colours.length - 1 ? "last" : 
                    "middle"
                  }
                />
              ))}
            </div>
            <p className="mt-4 text-sm text-brand-slate-500 italic">
              * Click any swatch to copy code. Hover to preview hex.
            </p>
          </div>
        )}
      </div>
    </main>
  );
}
